export const MAGAZINE_HTML = `<main class="book"><section class="page cover" id="page-1"><div class="issue-line"><span>Independent field magazine</span><span>2026 · No. 01</span></div><div class="title"><div class="kicker" style="color:#8ed6cd">Strategy · systems · governance · field practice</div><div class="mast">AI THAT<br>WORKS</div><div class="theme">From demo to operating system</div></div><div class="ring-art"><svg viewBox="0 0 460 720" fill="none" aria-hidden="true"><circle cx="260" cy="300" r="214" stroke="#5a879b"/><circle cx="260" cy="300" r="169" stroke="#3c7088"/><circle cx="260" cy="300" r="122" stroke="#27617a"/><circle cx="260" cy="300" r="72" fill="#e45f35"/><path d="M260 86V514" stroke="#6fcabd" stroke-width="2" stroke-dasharray="5 9"/><path d="M46 300H474" stroke="#6fcabd" stroke-width="2" stroke-dasharray="5 9"/><circle cx="260" cy="86" r="9" fill="#1f55d9"/><circle cx="474" cy="300" r="9" fill="#e45f35"/><circle cx="260" cy="514" r="9" fill="#08766c"/><circle cx="46" cy="300" r="9" fill="#fff"/><text x="260" y="296" fill="white" text-anchor="middle" font-family="Georgia" font-size="15" font-weight="700">MODEL</text><text x="260" y="318" fill="white" text-anchor="middle" font-family="Arial" font-size="9">one component</text><text x="260" y="52" fill="#b9dfdb" text-anchor="middle" font-family="Courier New" font-size="9">VALUE</text><text x="420" y="286" fill="#b9dfdb" text-anchor="middle" font-family="Courier New" font-size="9">AUTHORITY</text><text x="260" y="554" fill="#b9dfdb" text-anchor="middle" font-family="Courier New" font-size="9">EVIDENCE</text><text x="78" y="286" fill="#b9dfdb" text-anchor="middle" font-family="Courier New" font-size="9">WORKFLOW</text><path d="M80 608C145 570 206 622 260 588C326 546 375 602 426 555" stroke="#6fcabd" stroke-width="3"/><path d="M80 628C145 590 206 642 260 608C326 566 375 622 426 575" stroke="#e45f35" stroke-width="2" opacity=".8"/></svg></div><div class="coverlines"><div class="coverline"><b>09</b><span>The pilot was never the product</span></div><div class="coverline"><b>17</b><span>The model is the easiest part</span></div><div class="coverline"><b>24</b><span>RAG is an authorization system</span></div><div class="coverline"><b>29</b><span>Dashboards are not evidence</span></div></div><div class="editor">Edited by Subodh KC<br>Issue 01 · From demo to operating system</div><div class="folio">01</div></section><section class="page ad-haiec" id="page-2"><div class="ad-label">Advertisement</div><img class="logo" src="/magazine/img-1.png" alt="HAIEC emblem"><div class="copy"><div class="brand">HAIEC · AI EXPOSURE CONTROL</div><h1>YOUR AI IS LIVE.<br>CAN YOU RECONSTRUCT <em>ONE DECISION?</em></h1><p class="sub">HAIEC connects defined code findings, runtime attack tests, control mappings and tamper-evident artifacts into a technical evidence trail. Not another checklist. A record of what was tested, what failed and what supports the claim.</p></div><div class="haiec-report"><div class="label">Sample exposure file</div><div class="grade">C+</div><div class="caption">Moderate exposure · three critical gaps</div><div class="bar"><i style="width:64%"></i></div><div class="caption">Static finding â†’ runtime test â†’ evidence artifact</div></div><div class="evidence-pipeline"><div class="ep"><b>01 · Scan</b><span>Code and configuration</span><small>Defined rules identify missing controls and risky patterns.</small></div><div class="ep"><b>02 · Attack-test</b><span>Selected runtime paths</span><small>Authorized scenarios test behavior under adversarial input.</small></div><div class="ep"><b>03 · Bind</b><span>Control to result</span><small>Findings are linked to versions, tests and owners.</small></div><div class="ep"><b>04 · Preserve</b><span>Evidence artifact</span><small>Structured, timestamped output for technical review.</small></div></div><div class="ad-foot"><div><div class="print-url">HAIEC.COM</div><div class="ad-small">Scan the code. Test the behavior. Preserve the evidence.</div></div><div class="ad-qr"><span class="ad-small">Explore the exposure-control layer</span><img class="qr" src="/magazine/img-2.png" alt="QR code for HAIEC"></div></div><div class="folio">02</div></section><section class="page editor-page" id="page-3"><div class="running"><strong>EDITOR'S NOTE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="portrait-panel"><img src="/magazine/img-3.jpeg" alt="Subodh KC"></div><div class="editor-copy"><div class="kicker">THE DISTANCE BETWEEN THE DEMO AND THE BUSINESS</div><h1 class="display">AI rarely fails at the moment of demonstration.</h1><p class="lead" style="margin-top:15px">It fails laterâ€”when the output meets a workflow nobody owns, data nobody authorized, a handoff nobody designed, or an evidence request nobody prepared for.</p></div><div class="editor-thesis">The distinctive work is not making the model sound intelligent. It is designing the surrounding system so that intelligence produces a controlled result.</div><div class="editor-letter"><div><p class="drop">This issue begins where most AI coverage ends. The demonstration has worked. The model has generated a convincing answer. The team has seen enough to believe that a larger opportunity exists.</p><p>What happens next is less glamorous and more consequential. The capability must enter a real operating environmentâ€”one with permissions, system dependencies, changing data, constrained budgets, human accountability and customers who will experience every delay as part of the product.</p></div><div><p>The articles that follow draw from enterprise program delivery, production voice systems, secure retrieval architecture, failure analysis and governance tooling. They do not argue that every organization needs more control. They argue that the control must match the consequence.</p><p>A low-risk drafting assistant and an agent authorized to change customer records should not share the same approval path. A prototype and a production service should not be evaluated using the same evidence.</p></div><div><p>The issueâ€™s operating model has six layers: value, workflow, architecture, authority, evidence and learning. Value defines the reason to build. Workflow determines whether the work changes. Architecture determines what must connect. Authority defines what the system may do. Evidence preserves why it was allowed. Learning keeps the design valid after reality changes.</p><p style="font-family:Georgia,serif;font-size:16px;font-weight:700;margin-top:15px">That is the territory of AI That Works.</p><p class="kicker" style="margin-top:8px;color:#071927">SUBODH KC · EDITOR</p></div></div><div class="source">Biography and editorial position: SubodhKC.com/About. Product relationships and status disclosures appear on page 35.</div><div class="folio">03</div></section><section class="page white" id="page-4"><div class="running"><strong>CONTENTS</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.32in"><div class="kicker">INSIDE ISSUE 01</div><h1 class="display">From demo<br>to operating system.</h1><div class="contents-grid"><div><div class="contents-feature"><div class="num">09</div><h3>The Pilot Was Never the Product</h3><div class="mini-art"><svg viewBox="0 0 280 95"><rect width="280" height="95" fill="#eee8dd"/><path d="M10 72H112" stroke="#1f55d9" stroke-width="7"/><path d="M112 72H165" stroke="#e45f35" stroke-width="7"/><path d="M165 72H270" stroke="#08766c" stroke-width="7"/><text x="12" y="28" font-family="Georgia" font-size="17" font-weight="700">PILOT</text><text x="174" y="28" font-family="Georgia" font-size="17" font-weight="700">OPERATIONS</text><path d="M138 13V88" stroke="#ba2d25" stroke-width="2" stroke-dasharray="4 4"/></svg></div><p>Why a technically successful experiment can still leave the operating organization unchanged.</p></div><div class="contents-feature orange"><div class="num">17</div><h3>The Model Is the Easiest Part</h3><div class="mini-art dark"><svg viewBox="0 0 280 95"><rect width="280" height="95" fill="#202830"/><g transform="translate(18 16)"><svg viewBox="0 0 240 64" fill="none" aria-label="Live call waveform"><g stroke="#0B63F6" stroke-width="3" stroke-linecap="round"><path d="M9.6 27V37M19.2 23V41M28.8 18V46M38.4 24V40M48 14V50M57.6 10V54M67.2 21V43M76.8 23V41M86.4 12V52M96 5V59M105.6 18V46M115.2 22V42M124.8 25V39M134.4 16V48M144 9V55M153.6 15V49M163.2 20V44M172.8 24V40M182.4 19V45M192 13V51M201.6 6V58M211.2 17V47M220.8 23V41M230.4 26V38"/></g></svg></g></svg></div><p>Inside latency, state, retrieval, tool execution, handoffs and recovery in production voice AI.</p></div><div class="contents-feature teal"><div class="num">29</div><h3>Dashboards Are Not Evidence</h3><div class="mini-art"><svg viewBox="0 0 280 95"><rect width="280" height="95" fill="#f8f8f5"/><g font-family="Courier New" font-size="8"><text x="14" y="18">BUSINESS PURPOSE</text><text x="14" y="36">POLICY + INSTRUCTION</text><text x="14" y="54">DATA + IDENTITY</text><text x="14" y="72">TOOL + HUMAN ACTION</text></g><path d="M160 15H265M160 33H225M160 51H250M160 69H205" stroke="#111" stroke-width="8"/><path d="M160 87H270" stroke="#08766c" stroke-width="3"/></svg></div><p>How accountability disappears across instructions, data, authority, tools and human action.</p></div></div><div><h3 style="font-size:21px;border-top:4px solid var(--ink);padding-top:10px">Departments</h3><div class="departments" style="margin-top:10px"><div class="dept"><b>05</b><span>Issue manifesto</span></div><div class="dept"><b>06</b><span>The AI operating system</span></div><div class="dept"><b>08</b><span>Six questions before infrastructure</span></div><div class="dept"><b>16</b><span>Architecture decision sheet</span></div><div class="dept"><b>24</b><span>RAG is an authorization system</span></div><div class="dept"><b>26</b><span>The system quietly became different</span></div><div class="dept"><b>27</b><span>Why I open-sourced the safety layer</span></div><div class="dept"><b>28</b><span>Operatorâ€™s field notes</span></div><div class="dept"><b>35</b><span>Sources, status and disclosures</span></div></div><div class="side-note" style="margin-top:20px"><b>READ BY PROBLEM</b><p>Strategy and transformation: page 9. Architecture and production: page 17. Security and governance: page 29.</p></div></div></div></div></div><div class="folio">04</div></section><section class="page manifesto" id="page-5"><div class="running"><strong>MANIFESTO</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.55in"><div class="kicker">THE OPERATING THESIS</div><div class="giant">AI is not merely a feature once it influences customers, decisions, workflows, money, access or risk.</div><div class="six-words"><span>CUSTOMERS</span><span>DECISIONS</span><span>WORKFLOWS</span><span>MONEY</span><span>ACCESS</span><span>RISK</span></div><p class="lead" style="margin-top:28px;max-width:6.7in">It becomes operating infrastructure. Infrastructure must be owned. Its authority must be bounded. Its dependencies must be visible. Its failures must be recoverable. Its decisions must leave evidence.</p><div class="final">The question is no longer whether the model can answer. The question is whether the organization can operate what the model has started.</div></div></div><div class="folio">05</div></section><section class="page system-spread" id="page-6"><div class="running"><strong>THE AI OPERATING SYSTEM</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.55in"><div class="kicker">WHAT MUST EXIST BETWEEN THE DEMO AND THE BUSINESS</div><h1 class="display" style="font-size:43px;max-width:6.5in">The model sits inside a larger system of consequence.</h1><p class="lead" style="margin-top:14px;max-width:6.4in;color:#d7e3e8">A promising output only becomes value after it survives workflow ownership, architecture, authority, evidence and change.</p><div class="system-ring"><div class="system-core">MODEL<br><span style="font:700 7px 'Courier New'">ONE COMPONENT</span></div><div class="orbit-label o1"><b>VALUE</b><span>What baseline should move?</span></div><div class="orbit-label o2"><b>WORKFLOW</b><span>Who owns the changed work?</span></div><div class="orbit-label o3"><b>ARCHITECTURE</b><span>What must connect and recover?</span></div><div class="orbit-label o4"><b>AUTHORITY</b><span>What may the system do?</span></div><div class="orbit-label o5"><b>EVIDENCE</b><span>What can reconstruct the decision?</span></div><div class="orbit-label o6"><b>LEARNING</b><span>What changes after launch?</span></div></div></div></div><div class="source">Editorial framework synthesized from Cognitive Systems Management, architecture decision practice and production failure analysis.</div><div class="folio">06</div></section><section class="page system-spread" id="page-7"><div class="running"><strong>THE AI OPERATING SYSTEM</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.55in"><div class="kicker">READ THE SYSTEM IN BOTH DIRECTIONS</div><h1 class="display" style="font-size:44px">Value flows forward.<br>Failure travels backward.</h1><div class="cols2" style="margin-top:22px"><div class="copy"><p class="drop">A strategy team begins with a desired result. That result must survive the workflow, the architecture and the authority boundary before it becomes measurable value. Engineering teams often meet the same system from the opposite direction: a failed action, missing record or customer complaint reveals which earlier decision was never made.</p><p>This is why AI strategy and failure analysis should not operate as separate disciplines. Strategy asks what the system should create. Failure analysis asks which dependency could prevent the result, distort it or make it impossible to defend.</p><div class="side-note" style="background:rgba(49,87,232,.18);border-color:#7fabff;color:#fff"><b>OPERATORâ€™S RULE</b><p style="color:#e3edf2">Design the value path and the failure path at the same time.</p></div></div><div class="copy"><h3>One operating question per layer</h3><p><span class="keyword underline-blue">VALUE</span> â€” Which business baseline should move?</p><p><span class="keyword underline-blue">WORKFLOW</span> â€” Who owns the work after the model responds?</p><p><span class="keyword">ARCHITECTURE</span> â€” Which dependencies, tools and systems of record are involved?</p><p><span class="keyword underline-teal">AUTHORITY</span> â€” Which actions are permitted without escalation?</p><p><span class="keyword underline-teal">EVIDENCE</span> â€” Which records reconstruct what governed the action?</p><p><span class="keyword">LEARNING</span> â€” Which changes require the system or control to be updated?</p></div></div><div class="system-page-copy"><p><b>Forward:</b> business intent becomes operating design, system execution and a controlled outcome.</p><p><b>Backward:</b> an incident exposes missing state, authority, recovery, ownership or evidence.</p></div></div></div><div class="folio">07</div></section><section class="page white" id="page-8"><div class="running"><strong>THE BRIEF</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.48in"><div class="kicker">SIX QUESTIONS BEFORE AI BECOMES INFRASTRUCTURE</div><h1 class="display">Ask these before selecting another model.</h1><div class="brief-list"><div class="brief-item"><div class="n">01</div><h3>What business baseline should change?</h3><p>Without a baseline, output volume can be mistaken for business value.</p></div><div class="brief-item"><div class="n">02</div><h3>Who owns the modified workflow?</h3><p>The pilot team is temporary. The workflow owner remains after launch.</p></div><div class="brief-item"><div class="n">03</div><h3>Which data is the AI authorized to use?</h3><p>Relevant information is not automatically permitted information.</p></div><div class="brief-item"><div class="n">04</div><h3>Which actions may it execute?</h3><p>Recommendation, preparation and execution require different authority.</p></div><div class="brief-item"><div class="n">05</div><h3>What happens when the preferred path fails?</h3><p>A retry is not a recovery plan; state and ownership must survive.</p></div><div class="brief-item"><div class="n">06</div><h3>What evidence must remain afterward?</h3><p>The record must reconstruct instructions, sources, permissions, tests and human action.</p></div></div><div class="pullquote" style="margin-top:18px">Most deployment risk enters before the first line of production codeâ€”when the organization mistakes a model decision for an operating decision.</div></div></div><div class="folio">08</div></section><section class="page f1-opener" id="page-9"><div class="red-block"></div><div class="blue-circle"></div><div class="feature-tag">Feature 01 · Strategy & programs</div><h1 class="headline">THE PILOT<br>WAS NEVER<br>THE PRODUCT</h1><p class="dek">A pilot proves that a model can perform a bounded task. It does not prove that the organization can absorb, integrate, govern and sustain the changed work.</p><div class="readtime">A six-page field feature · practitioner analysis</div><div class="folio">09</div></section><section class="page warm" id="page-10"><div class="running"><strong>FEATURE 01 · THE PILOT WAS NEVER THE PRODUCT</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div class="article-top"><div class="article-titleline"><div class="n">01</div><h2>The pilot answered the question it was given.</h2></div><div class="cols-rail"><div class="copy"><p class="drop">The demonstration was convincing. A model analyzed a complex input, identified the issue and produced a useful recommendation. The room moved quickly from curiosity to deployment language: How soon can this go live? What else can we connect? Which team should use it first?</p><p>That reaction is understandable. A good pilot compresses uncertainty. It can show that a task is technically possible, that users recognize the value and that the organization should invest in deeper evaluation.</p><p>The failure begins when the pilot is asked to prove more than it measured. A bounded experiment with curated inputs, temporary support and limited users cannot establish whether the future operating environment will preserve the same result.</p><h3>What pilots are good at</h3><p>Pilots are useful for testing feasibility, early model performance, workflow hypotheses and user response. They help reject weak ideas cheaply. They help expose unknowns before architecture hardens.</p></div><div class="copy"><h3>The protected room</h3><p>During a demonstration, someone knows which input to provide, which result to expect and how to explain a rough edge. Data is usually cleaner. The number of paths is smaller. When a dependency fails, the people who built the system are nearby.</p><p>Production removes that protection. Inputs arrive incomplete. Users interrupt. policies change. identities are ambiguous. Source systems disagree. A tool returns success while the downstream record remains unchanged.</p><p>The model can continue performing exactly as tested while the overall capability fails.</p><div class="pullquote">The pilot tested the model inside a protected room. Production required the organization outside that room to change.</div></div><aside><div class="kicker" style="color:#071927">PILOT SCORECARD</div><table class="score-table"><tr><th>Measured</th><th>Often omitted</th></tr><tr><td>Model output</td><td>Workflow ownership</td></tr><tr><td>Task accuracy</td><td>Integration reliability</td></tr><tr><td>User reaction</td><td>Recovery behavior</td></tr><tr><td>Demo speed</td><td>Operating cost</td></tr><tr><td>Curated input</td><td>Real-world variation</td></tr></table><div class="side-note orange"><b>EDITORIAL LIMIT</b><p>This is an operating framework, not a statistical claim that all pilots fail for the same reason.</p></div></aside></div></div></div><div class="source">Adapted from Cognitive Systems Management and enterprise AI-integration essays. Practitioner analysis; not a population study of all AI pilots.</div><div class="folio">10</div></section><section class="page white" id="page-11"><div class="running"><strong>FEATURE 01 · THE PILOT WAS NEVER THE PRODUCT</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div class="article-top"><div class="article-titleline"><div class="n">02</div><h2>Output is not an operating outcome.</h2></div><div class="cols2"><div class="copy"><p class="drop">A model can produce a correct answer while the business continues operating exactly as before. A call is summarized but no follow-up task is assigned. A document is classified but the system of record is never updated. A risk is identified but no release gate responds. An appointment is verbally confirmed while the calendar remains unchanged.</p><p>In each case, the AI has created output. It has not created a controlled outcome.</p><h3>The workflow remained unchanged</h3><p>Most work extends beyond the point where a model responds. Someone receives the result, validates it, records it, acts on it and becomes accountable for what follows. When these steps remain manual or undefined, the business may gain information without gaining capacity.</p><p>This distinction matters because pilot metrics often favor what is easiest to observe: responses generated, minutes saved, documents processed or user satisfaction. Those measures can be useful, but they do not show whether the end-to-end business process improved.</p><div class="side-note"><b>OPERATORâ€™S RULE</b><p>An AI interaction is not complete when the model answers. It is complete when the workflow reaches a validated, recorded and assigned outcome.</p></div></div><div class="copy"><div class="article-titleline" style="grid-template-columns:70px 1fr;margin-top:0"><div class="n" style="color:var(--orange)">03</div><h2>Architecture determines whether the operating model is possible.</h2></div><p>Integration is often postponed until the pilot earns approval. That reverses the logic. Identity, permissions, source systems, data freshness, tenant boundaries, APIs, logging, failure handling and support ownership are not implementation details. They determine what the system can safely become.</p><p>A pilot that writes only to a temporary interface may hide the hardest questions: Which record wins when two systems disagree? What happens when the tool call times out? Can the AI see information the user cannot? Which event confirms that the transaction actually completed?</p><h3>The production path is longer</h3><p><span class="keyword underline-blue">IDENTITY</span> determines who is asking. <span class="keyword underline-blue">AUTHORIZED DATA</span> determines what context is permitted. <span class="keyword">TOOLS</span> convert language into action. <span class="keyword mark-orange">VALIDATION</span> proves whether the action completed. <span class="keyword underline-teal">EVIDENCE</span> preserves what governed the result.</p><p>When architecture is deferred, the organization may approve an idea whose intended authority, latency, cost or control model is not technically achievable.</p></div></div><div class="pullquote" style="margin-top:15px">Integration is not the final engineering phase. It is part of deciding whether the proposed operating model can exist.</div></div></div><div class="folio">11</div></section><section class="page warm" id="page-12"><div class="running"><strong>FEATURE 01 · THE PILOT WAS NEVER THE PRODUCT</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div class="article-top"><div class="kicker">FIVE LAYERS THAT KILL THE PILOT</div><h1 class="display small">The technical demonstration can survive every one of these failures.</h1><div class="failure-chain"><div class="failure-row"><strong>01</strong><b>No meaningful baseline</b><span>Output volume looks like value</span></div><div class="failure-row"><strong>02</strong><b>No workflow owner</b><span>The pilot team becomes permanent support</span></div><div class="failure-row"><strong>03</strong><b>Integration begins after approval</b><span>Critical dependencies surface late</span></div><div class="failure-row"><strong>04</strong><b>Human authority remains undefined</b><span>Responsibility exists only in policy language</span></div><div class="failure-row"><strong>05</strong><b>No operating program</b><span>Launch has no adoption, monitoring or budget model</span></div></div><div class="cols2" style="margin-top:17px"><div class="copy"><h3>Why success hides the gap</h3><p>The pilotâ€™s narrow boundary isolates the model from the organizational work required to sustain it. Temporary manual steps compensate for missing integrations. Builders answer questions that a future support team will receive. Decision-makers assume human review will occur without defining the role, threshold or response time.</p><p>That creates a dangerous form of success. The demonstration appears to reduce risk at the same moment it is deferring the highest-consequence questions.</p></div><div class="copy"><h3>The second-order effect</h3><p>Once executives announce the pilot, momentum makes later constraints harder to discuss. Security requirements are treated as delay. Workflow redesign becomes change resistance. The architecture team inherits a promise made before dependencies were mapped.</p><p>A more strategic pilot is designed to expose the operating constraints early. Its job is not only to prove that the model can work. It is to discover what the organization must become in order to use it.</p></div></div><div class="side-note orange"><b>FAILURE MODE</b><p>The pilot is approved, but the future workflow has no named owner, release gate, operating budget or evidence requirement.</p></div></div></div><div class="folio">12</div></section><section class="page white" id="page-13"><div class="running"><strong>FEATURE 01 · THE PILOT WAS NEVER THE PRODUCT</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div class="article-top"><div class="article-titleline"><div class="n">04</div><h2>Human oversight is not a button.</h2></div><div class="cols2"><div class="copy"><p class="drop">Organizations often claim that a person remains responsible for the AIâ€™s decision. That statement may be true in principle and meaningless in operation.</p><p>Real oversight requires decision rights. Which actions may the system take independently? Which require confirmation? Which require specialist approval? What confidence or risk threshold triggers escalation? Who responds when the designated reviewer is unavailable? What record proves that review occurred?</p><p>Without these answers, â€œhuman in the loopâ€ describes an aspiration, not a control.</p><h3>Authority must be designed</h3><p>A useful authority model separates five modes: recommend, prepare, execute within defined limits, escalate and refuse. The mode should depend on the consequenceâ€”not on whether the model appears confident.</p></div><div class="copy"><h3>A program coordinates the owners</h3><p>Moving AI into production crosses product, engineering, security, data, operations, finance, support and governance. No single AI team can resolve those dependencies after the pilot.</p><p>Large application portfolios teach a basic operating lesson: a system cannot be governed in isolation from its dependencies, release windows, ownership model and support structure. AI intensifies that requirement because the same conversational surface may retrieve data, call tools and influence decisions across several systems.</p><p>The missing layer is frequently not another model. It is coordinated execution.</p><div class="pullquote">Responsibility becomes real only when a named person owns a defined decision at a defined point in the workflow.</div></div></div><div class="owner-grid"><div class="owner"><b>Outcome owner</b><p>Owns the measurable result and decides whether the capability deserves continued investment.</p></div><div class="owner"><b>Workflow owner</b><p>Owns the work before and after the AI acts, including exception and escalation paths.</p></div><div class="owner"><b>Architecture owner</b><p>Owns identity, systems, data, integration, observability and technical recovery.</p></div><div class="owner"><b>Authority owner</b><p>Defines which actions are recommended, prepared, executed, escalated or refused.</p></div><div class="owner"><b>Adoption owner</b><p>Owns training, role change, communication and whether the new behavior enters practice.</p></div><div class="owner"><b>Evidence owner</b><p>Owns the records, retention and ability to reconstruct what governed the action.</p></div></div></div></div><div class="source">Career framing uses the publicly documented 53-application enterprise portfolio; no confidential application details or unsupported portfolio values are included.</div><div class="folio">13</div></section><section class="page warm" id="page-14"><div class="running"><strong>FEATURE 01 · THE PILOT WAS NEVER THE PRODUCT</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div class="article-top"><div class="kicker">A PILOT NEEDS A PROGRAM</div><h1 class="display small">Do not ask only whether the pilot worked. Ask whether the operating model exists.</h1><div class="cols2" style="margin-top:20px"><div class="copy"><h3>Production-readiness questions</h3><p><b>1.</b> What measurable baseline should change?</p><p><b>2.</b> Who owns the workflow after deployment?</p><p><b>3.</b> Which systems and data sources must connect?</p><p><b>4.</b> What authority will the AI receive?</p><p><b>5.</b> Where does human control enter?</p><p><b>6.</b> How will failure be detected and recovered?</p><p><b>7.</b> Which evidence must remain?</p><p><b>8.</b> Who operates the system after the pilot team leaves?</p></div><div class="copy"><h3>Use this Monday</h3><p>Select one active AI pilot and write the future workflow in plain language. Name the person who owns the result after launch. Identify the first dependency that could prevent production. Define one action the AI may not take without approval.</p><p>Then compare those answers with the pilot plan. The distance between them is not administrative overhead. It is the real deployment program.</p><div class="side-note teal"><b>THE ONE-MINUTE VERSION</b><p>A successful experiment proves model capability. A production capability requires workflow ownership, integration, authority, adoption, recovery and evidence.</p></div></div></div><div class="pullquote" style="margin-top:24px">A successful pilot answers, â€œCan the model perform the task?â€ A production program answers, â€œCan the organization operate the consequences?â€</div></div></div><div class="folio">14</div></section><section class="page ad-security" id="page-15"><div class="ad-label">Advertisement</div><div class="copy"><div class="kicker" style="color:#071927">HAIEC · TECHNICAL AI SECURITY ASSESSMENT</div><h1>THE DEMO TESTED THE HAPPY PATH.<br><span>WE TEST THE PATH THAT FIGHTS BACK.</span></h1><p class="lead">A scoped assessment of selected AI attack surfaces, authorization gaps and evidence failuresâ€”defined before testing begins.</p><div style="margin-top:30px"><p><b>The assessment starts with four controls:</b></p><p>Written authorization to test. A fixed system boundary. Agreed scenarios and exclusions. A deliverable that separates observed findings from interpretation.</p></div></div><div class="diag"><div class="kicker" style="color:#9bd2cc">SELECTED ATTACK SURFACES</div><h2 style="font-size:26px">What the demonstration did not attempt.</h2><div class="attack-map"><div class="attack-row"><div class="x">!</div><b>Prompt injection</b><span>TEST</span></div><div class="attack-row"><div class="x">!</div><b>System-prompt extraction</b><span>TEST</span></div><div class="attack-row"><div class="x">!</div><b>Unauthorized tools</b><span>TEST</span></div><div class="attack-row"><div class="x">!</div><b>RAG poisoning</b><span>TEST</span></div><div class="attack-row"><div class="x">!</div><b>Tenant isolation</b><span>TEST</span></div></div><div class="side-note orange" style="background:rgba(228,95,53,.12);color:#fff"><b>NOT A GUARANTEE</b><p style="color:#dce6ea">Testing selected paths does not prove the absence of every vulnerability. Scope and limitations remain part of the result.</p></div></div><div class="security-scope"><b>REQUEST A SCOPED AI SECURITY ASSESSMENT</b><br>HAIEC.COM/SOLUTIONS/AI-SECURITY</div><div class="ad-foot"><div class="print-url">HAIEC.COM/SOLUTIONS/AI-SECURITY</div><div class="ad-qr"><span class="ad-small">Assessment overview</span><img class="qr" src="/magazine/img-4.png" alt="QR code for AI security assessment"></div></div><div class="folio">15</div></section><section class="page white" id="page-16"><div class="running"><strong>FIELD TOOL · ARCHITECTURE DECISION SHEET</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.5in"><div class="kicker">BEFORE YOU SELECT THE MODEL</div><h1 class="display small">Eight decisions that determine the architecture.</h1><p class="lead" style="margin-top:13px;max-width:6.5in">Model choice matters. It matters after the organization defines the outcome, workflow, authority, data, recovery and evidence the system must support.</p><div class="brief-list"><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">01</div><h3 style="font-size:14px">Outcome</h3><p style="font-size:10px;color:#071927">Which measurable baseline must change?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">02</div><h3 style="font-size:14px">Owner</h3><p style="font-size:10px;color:#071927">Who owns the workflow after the AI responds?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">03</div><h3 style="font-size:14px">Data</h3><p style="font-size:10px;color:#071927">What may the system accessâ€”and what is prohibited?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">04</div><h3 style="font-size:14px">Authority</h3><p style="font-size:10px;color:#071927">What may it recommend, prepare or execute?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">05</div><h3 style="font-size:14px">Recovery</h3><p style="font-size:10px;color:#071927">What happens when the preferred path fails?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">06</div><h3 style="font-size:14px">Human control</h3><p style="font-size:10px;color:#071927">Where can a person pause, approve or override?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">07</div><h3 style="font-size:14px">Evidence</h3><p style="font-size:10px;color:#071927">Which records must reconstruct the action?</p></div><div class="brief-item" style="grid-template-columns:44px 90px 1fr"><div class="n" style="font-size:24px">08</div><h3 style="font-size:14px">Release</h3><p style="font-size:10px;color:#071927">What must be true before production use?</p></div></div><div class="side-note" style="margin-top:15px"><b>WORKING METHOD</b><p>Write one sentence for each question. Any answer that begins with â€œthe AI team will decide laterâ€ is an unresolved operating dependency.</p></div><div style="position:absolute;right:.55in;bottom:.55in;display:flex;align-items:end;gap:10px"><div class="print-url">SUBODHKC.COM/RESEARCH</div><img class="qr" src="/magazine/img-5.png" alt="QR to research and frameworks"></div></div></div><div class="folio">16</div></section><section class="page f2-opener" id="page-17"><div class="kmark"><svg viewBox="0 0 24 24" fill="none" aria-label="Kestrel mark"><path d="M4 4.5L20 2L12.4 9.6L20 22L4 13.4L9.6 9.4L4 4.5Z" fill="#0B63F6" opacity=".88"/><path d="M9.6 9.4L20 2L12.4 9.6L20 22L9.6 9.4Z" fill="#93C5FD" opacity=".7"/></svg></div><div class="feature-tag" style="position:absolute;left:.58in;top:.68in;font:700 8px 'Courier New';letter-spacing:.14em;text-transform:uppercase;color:#8ed2ca">Feature 02 · Systems & field engineering</div><h1 class="headline">THE MODEL<br>IS THE <span>EASIEST</span><br>PART</h1><p class="dek">A caller hears one voice. The system must coordinate telephony, audio, state, retrieval, tools, handoffs, observability and recoveryâ€”without exposing the complexity.</p><div class="wave"><svg viewBox="0 0 240 64" fill="none" aria-label="Live call waveform"><g stroke="#0B63F6" stroke-width="3" stroke-linecap="round"><path d="M9.6 27V37M19.2 23V41M28.8 18V46M38.4 24V40M48 14V50M57.6 10V54M67.2 21V43M76.8 23V41M86.4 12V52M96 5V59M105.6 18V46M115.2 22V42M124.8 25V39M134.4 16V48M144 9V55M153.6 15V49M163.2 20V44M172.8 24V40M182.4 19V45M192 13V51M201.6 6V58M211.2 17V47M220.8 23V41M230.4 26V38"/></g></svg></div><div class="folio">17</div></section><section class="page tech-page" id="page-18"><div class="running"><strong>FEATURE 02 · WHAT THE CALLER HEARD</strong><span>CENTER SPREAD · PART 1</span></div><div class="center-timeline"><div class="kicker">A RECONSTRUCTED COMPOSITE BASED ON REAL FAILURE PATTERNS</div><h1 class="display small">The conversation sounded almost successful.</h1><p style="color:#cfdae0;max-width:6in;margin-top:10px">The call connected. The greeting was correct. The caller requested an appointment. The AI appeared to confirm it. No usable business outcome followed.</p><div class="time-labels"><span>0s</span><span>2s</span><span>4s</span><span>6s</span><span>8s</span></div><div class="timeline-axis"></div><div style="margin-top:.6in"><div class="lane"><div class="lane-title">WHAT THE CALLER HEARD</div><div class="lane-track"><div class="event gray" style="left:0%;width:10%">ring</div></div></div><div class="lane"><div class="lane-title">GREETING</div><div class="lane-track"><div class="event teal" style="left:8%;width:27%">Hello, how can I help?</div></div></div><div class="lane"><div class="lane-title">CALLER</div><div class="lane-track"><div class="event gray" style="left:35%;width:28%">I need Friday afternoon</div></div></div><div class="lane"><div class="lane-title">SILENCE</div><div class="lane-track"><div class="event orange" style="left:63%;width:22%">waiting</div></div></div><div class="lane"><div class="lane-title">RESPONSE</div><div class="lane-track"><div class="event teal" style="left:84%;width:16%">I can help with thatâ€¦</div></div></div></div><div style="height:.65in;margin-top:22px"><svg viewBox="0 0 240 64" fill="none" aria-label="Live call waveform"><g stroke="#0B63F6" stroke-width="3" stroke-linecap="round"><path d="M9.6 27V37M19.2 23V41M28.8 18V46M38.4 24V40M48 14V50M57.6 10V54M67.2 21V43M76.8 23V41M86.4 12V52M96 5V59M105.6 18V46M115.2 22V42M124.8 25V39M134.4 16V48M144 9V55M153.6 15V49M163.2 20V44M172.8 24V40M182.4 19V45M192 13V51M201.6 6V58M211.2 17V47M220.8 23V41M230.4 26V38"/></g></svg></div><div class="latency-note">The caller does not experience components. The caller experiences accumulated delay, lost state and whether the business receives a usable outcome.</div></div><div class="source">Composite scenario based on redacted engineering and testing patterns. Not a verbatim customer call.</div><div class="folio">18</div></section><section class="page tech-page" id="page-19"><div class="running"><strong>FEATURE 02 · WHAT THE SYSTEM WAS DOING</strong><span>CENTER SPREAD · PART 2</span></div><div class="center-timeline"><div class="kicker">THE SAME EIGHT SECONDS INSIDE THE STACK</div><h1 class="display small">Latency was accumulated waitingâ€”not one slow model.</h1><p style="color:#cfdae0;max-width:6.2in;margin-top:10px">Every layer added time, state and a new failure boundary. The caller judged the combined result.</p><div class="time-labels"><span>0s</span><span>2s</span><span>4s</span><span>6s</span><span>8s</span></div><div class="timeline-axis"></div><div style="margin-top:.6in"><div class="lane"><div class="lane-title">TELEPHONY</div><div class="lane-track"><div class="event gray" style="left:0%;width:13%">connect</div><div class="event teal" style="left:13%;width:12%">stream open</div></div></div><div class="lane"><div class="lane-title">SPEECH</div><div class="lane-track"><div class="event gray" style="left:25%;width:10%">buffer</div><div class="event teal" style="left:35%;width:18%">transcribe</div></div></div><div class="lane"><div class="lane-title">STATE</div><div class="lane-track"><div class="event gray" style="left:43%;width:10%">tenant</div><div class="event orange" style="left:53%;width:13%">booking state</div></div></div><div class="lane"><div class="lane-title">RETRIEVAL</div><div class="lane-track"><div class="event teal" style="left:57%;width:15%">knowledge</div></div></div><div class="lane"><div class="lane-title">MODEL</div><div class="lane-track"><div class="event gray" style="left:69%;width:17%">inference</div></div></div><div class="lane"><div class="lane-title">TOOL</div><div class="lane-track"><div class="event orange" style="left:79%;width:12%">calendar call</div><div class="event orange" style="left:91%;width:9%">timeout</div></div></div><div class="lane"><div class="lane-title">VOICE</div><div class="lane-track"><div class="event teal" style="left:85%;width:13%">TTS</div></div></div><div class="lane"><div class="lane-title">RECORD</div><div class="lane-track"><div class="event gray" style="left:88%;width:12%">event log</div></div></div></div><div class="latency-note">There is no single â€œAI response time.â€ End-to-end experience includes connection, buffering, turn detection, transcription, retrieval, inference, tool execution, speech generation and recovery.</div></div><div class="folio">19</div></section><section class="page tech-page" id="page-20"><div class="running"><strong>FEATURE 02 · THE MODEL IS THE EASIEST PART</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">EVERY HANDOFF CREATES STATE</div><h1 class="display small">The system can remember the sentence and still lose the task.</h1><div class="cols2" style="margin-top:15px"><div class="copy"><p class="drop" style="color:#dce7ec">â€œI need someone Friday afternoonâ€ sounds like one request. Operationally it is a bundle of state: the service, caller, location, date, time range, timezone, availability check, booking status and follow-up channel.</p><p>If any element is dropped between the conversation engine, calendar, call-control layer and business record, the system may continue speaking coherently while the outcome fails.</p><p>Many apparent intelligence problems are state problems. The model receives an incomplete history, the wrong tenant configuration or a stale tool result, then responds rationally to the wrong operating context.</p></div><div class="copy"><h3>State must have an owner</h3><p>Distributed systems routinely pass work between services. Voice systems add human interruption, ambiguity and real-time pressure. The architecture must define where state is created, where it is authoritative, how it is validated and how it survives retries.</p><p>â€œThe call completedâ€ is not sufficient. Did the booking persist? Did the transfer connect? Did the transcript attach to the correct call? Did the follow-up reach the team? Each statement requires a separate completion signal.</p><div class="side-note orange" style="background:rgba(228,95,53,.14);color:#fff"><b>FAILURE MODE</b><p style="color:#dce7ec">The conversation sounds successful because the model remembers the request. The business fails because the workflow state did not survive the handoff.</p></div></div></div><div class="state-list"><div class="state"><b>Caller identity</b><p>Who is speaking and which number or account is involved?</p></div><div class="state"><b>Tenant identity</b><p>Which business configuration and knowledge base apply?</p></div><div class="state"><b>Conversation state</b><p>What has already been asked, confirmed or refused?</p></div><div class="state"><b>Booking state</b><p>Service, date, time range, location, timezone and confirmation status.</p></div><div class="state"><b>Tool state</b><p>Was the calendar or CRM action requested, accepted and persisted?</p></div><div class="state"><b>Transfer state</b><p>Who should receive the handoff, with which context and disposition?</p></div><div class="state"><b>Recording state</b><p>Which audio, transcript and events were actually preserved?</p></div><div class="state"><b>Recovery state</b><p>What failed, what remains usable and who owns the next action?</p></div></div></div></div><div class="folio">20</div></section><section class="page tech-page" id="page-21"><div class="running"><strong>FEATURE 02 · THE MODEL IS THE EASIEST PART</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">THE FAILURE PATH IS PART OF THE PRODUCT</div><h1 class="display small">Fallback is not recovery.</h1><div class="cols2" style="margin-top:16px"><div class="copy"><p class="drop" style="color:#dce7ec">A fallback substitutes another behavior. A recovery path recognizes failure, protects the user, preserves state, chooses an alternative, records what happened and leaves the business with a usable next action.</p><p>Repeating the prompt is a fallback. Telling the caller to try later is a fallback. Transferring without context is a fallback. These responses may keep the call moving while discarding the work already completed.</p><h3>Recovery begins with validation</h3><p>The system should not treat a tool invocation as success. It should validate the downstream result. A calendar request that returns an identifier but does not appear on the expected calendar is incomplete. A transfer leg that is dialed but not answered is not a handoff.</p></div><div class="copy"><h3>Design the failure vocabulary</h3><p>The AI needs explicit language for partial success, retry, alternate option, human escalation and refusal. The business needs corresponding records: what failed, which state remains valid, whether the customer was informed and who owns the next step.</p><p>This is where customer experience and observability meet. A courteous apology without an internal recovery record protects the conversation but not the operation. A perfect internal error log without a clear customer response protects engineering but not trust.</p><div class="pullquote" style="color:#fff;border-color:var(--orange)">The recovery path should be designed with the same care as the happy pathâ€”because customers eventually use both.</div></div></div><div class="recovery-flow"><div class="step"><b>Preferred action</b><p>Attempt the requested operation.</p></div><div class="step"><b>Validate</b><p>Confirm the downstream system actually changed.</p></div><div class="step"><b>Preserve state</b><p>Keep usable details when the action fails.</p></div><div class="step"><b>Choose alternative</b><p>Offer another time, capture callback or route.</p></div><div class="step"><b>Record ownership</b><p>Create the evidence and next-action owner.</p></div></div></div></div><div class="folio">21</div></section><section class="page tech-page" id="page-22"><div class="running"><strong>FEATURE 02 · THE MODEL IS THE EASIEST PART</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">WHAT WE FINALLY HAD TO OWN</div><h1 class="display small">The tools worked individually. The missing layer lived between them.</h1><p class="lead" style="color:#d8e4e9;margin-top:14px;max-width:6.4in">The architecture had to coordinate one operating model across conversation, state, retrieval, authority, recovery and evidence.</p><div class="owner-grid"><div class="owner" style="background:#2a343d;color:#fff;border-color:#1f55d9"><b style="color:#9ec8ff">Orchestration</b><p style="color:#d6e1e6">Turn-taking, interruption and request lifecycle.</p></div><div class="owner" style="background:#2a343d;color:#fff;border-color:#08766c"><b style="color:#9ec8ff">State</b><p style="color:#d6e1e6">Identity, tenant, conversation and workflow status.</p></div><div class="owner" style="background:#2a343d;color:#fff;border-color:#e45f35"><b style="color:#9ec8ff">Retrieval</b><p style="color:#d6e1e6">Approved knowledge, version and authorization.</p></div><div class="owner" style="background:#2a343d;color:#fff;border-color:#1f55d9"><b style="color:#9ec8ff">Tool authority</b><p style="color:#d6e1e6">Which actions are permitted and under what limits.</p></div><div class="owner" style="background:#2a343d;color:#fff;border-color:#08766c"><b style="color:#9ec8ff">Recovery</b><p style="color:#d6e1e6">Validation, alternative paths and human escalation.</p></div><div class="owner" style="background:#2a343d;color:#fff;border-color:#e45f35"><b style="color:#9ec8ff">Observability</b><p style="color:#d6e1e6">Events, recordings, outcomes and evidence.</p></div></div><div class="cols2" style="margin-top:14px"><div class="copy"><h3>What changed from the early approach</h3><p>Vendor abstractions remained useful, but they could not own the complete business outcome. The design moved toward explicit state transitions, visible tool results, tenant-aware retrieval, recovery events and a record that separated â€œthe AI said itâ€ from â€œthe workflow completed it.â€</p></div><div class="copy"><h3>Use this Monday</h3><p>Draw one customer-critical request from the first network event to the final business record. Add every external dependency. Mark where state changes ownership. Define one fallback and one real recovery path. Identify the record that proves completion.</p></div></div><div class="pullquote" style="color:#fff;margin-top:18px">The model may generate the answer. The operating system determines whether the customer receives an outcome.</div></div></div><div class="source">Product lessons are presented as practitioner analysis. Kestrel Voice status and relationship are disclosed on page 35.</div><div class="folio">22</div></section><section class="page ad-front" id="page-23"><div class="ad-label">Advertisement</div><div class="front-red"></div><div class="front-copy"><div class="front-wordmark">FRONT / OF AI · WEEKLY BRIEFING</div><h1>AI MOVES FASTER THAN THE MEETING WHERE YOU DECIDE <em>WHAT TO DO ABOUT IT.</em></h1><p class="lead" style="max-width:6.2in">One source-linked weekly brief for leaders carrying the consequence across architecture, security, product, governance and enterprise systems.</p></div><div class="brief-preview"><div class="signal-stack"><div class="kicker" style="color:#111;margin-top:10px">SIGNALS THAT CHANGED THE WEEK</div><div class="signal"><time>06:40</time><b>Security team discloses new agent-tool vulnerability</b><span>CRITICAL</span></div><div class="signal"><time>07:15</time><b>Major model changes enterprise pricing and context limits</b><span>HIGH</span></div><div class="signal"><time>08:10</time><b>Regulator publishes implementation guidance</b><span>HIGH</span></div><div class="signal"><time>09:30</time><b>Open-source framework adds production evaluation controls</b><span>WATCH</span></div><div class="signal"><time>11:05</time><b>Cloud platform changes managed-model availability</b><span>MEDIUM</span></div></div><div class="brief-cover"><div class="front-wordmark">FRONT / OF AI</div><h3 style="margin:12px 0">The Monday Brief</h3><div class="caption">What changed. Why it matters. What to do next.</div><div class="story"><b>MODEL ECONOMICS</b><p>Which pricing and context changes alter the architecture decision.</p></div><div class="story"><b>SECURITY</b><p>Which disclosed attack path requires review now.</p></div><div class="story"><b>GOVERNANCE</b><p>Which legal or standard change affects the operating plan.</p></div><div class="story"><b>NEXT ACTION</b><p>Three decisions to carry into the week.</p></div></div></div><div class="ad-foot"><div><div class="print-url">FRONTOFAI.COM/BRIEFING</div><div class="ad-small">Role views · editorial impact scoring · original-source links</div></div><div class="ad-qr"><span class="ad-small">Read the weekly briefing</span><img class="qr" src="/magazine/img-6.png" alt="QR to FrontOfAI briefing"></div></div><div class="folio">23</div></section><section class="page white" id="page-24"><div class="running"><strong>FIELD GUIDE · SECURE RETRIEVAL</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">RAG IS AN AUTHORIZATION SYSTEM · PART 1</div><h1 class="display small">Retrieval is not merely search.</h1><p class="lead" style="margin-top:13px">A production system must decide which evidence is relevant, current, trustworthy and permitted for the specific user and decision.</p><div class="rag-flow"><div class="rag-step"><b>Identity</b><span>Who is asking?</span></div><div class="rag-step"><b>Permission</b><span>Which records are allowed?</span></div><div class="rag-step"><b>Retrieval</b><span>Exact + semantic + metadata</span></div><div class="rag-step"><b>Validation</b><span>Current, trusted, untampered</span></div><div class="rag-step"><b>Context</b><span>Only authorized evidence</span></div><div class="rag-step"><b>Record</b><span>Citation + audit event</span></div></div><div class="cols2" style="margin-top:14px"><div class="copy"><h3>Hybrid search is an operating requirement</h3><p>Semantic similarity is useful for meaning. Exact search is necessary for identifiers, account numbers, policy clauses and product codes. Metadata filters determine tenant, document type, region, effective date and access class.</p><p>A robust retrieval path combines these signals rather than assuming one embedding score represents truth.</p><h3>The source must still be valid</h3><p>Relevant text can be outdated, superseded, incomplete or maliciously inserted. Production retrieval should preserve version, provenance, effective date and source ownershipâ€”then reject or escalate when the evidence is weak.</p></div><div class="copy"><h3>The database check is not secondary</h3><p>Permissions should narrow the candidate records before sensitive content reaches the model. Asking the model to ignore unauthorized context after retrieval is not an access control.</p><p>The architecture should make the forbidden path technically unavailable: identity â†’ permission filter â†’ retrieval â†’ validation â†’ authorized context.</p><div class="side-note orange"><b>FAILURE MODE</b><p>The system retrieves the correct document for the wrong user.</p></div><h3>Citations are part of the product</h3><p>A citation is not decoration. It allows the user, reviewer and incident responder to verify what influenced the answer and which version applied.</p></div></div></div></div><div class="source">Adapted from â€œSecure Enterprise RAG Architecture,â€ SubodhKC.com. Design argument; not a formal definition of all RAG systems.</div><div class="folio">24</div></section><section class="page warm" id="page-25"><div class="running"><strong>FIELD GUIDE · SECURE RETRIEVAL</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">RAG IS AN AUTHORIZATION SYSTEM · PART 2</div><h1 class="display small">Authorization must happen before retrieval.</h1><div class="path-compare" style="margin-top:18px"><div class="path-box"><h3>Unsafe path</h3><ol><li>Search every document.</li><li>Send restricted results to the model.</li><li>Ask the prompt to respect permissions.</li><li>Display an answer if the model complies.</li></ol><p><b>Risk:</b> sensitive context has already crossed the boundary.</p></div><div class="path-box safe"><h3>Controlled path</h3><ol><li>Resolve identity and tenant.</li><li>Apply row-level and metadata permissions.</li><li>Retrieve only eligible sources.</li><li>Validate source and create the record.</li></ol><p><b>Result:</b> the forbidden document never enters the prompt.</p></div></div><div class="cols2" style="margin-top:18px"><div class="copy"><h3>Poisoning changes the trust model</h3><p>RAG turns documents into executable influence. A malicious or careless edit can redirect answers without changing application code. Ingestion therefore needs source approval, content hashing, version history, anomaly detection and a way to revoke or quarantine evidence.</p><p>The higher the systemâ€™s authority, the stronger the source-control requirement. A chat answer and an agent tool call should not inherit the same trust threshold.</p></div><div class="copy"><h3>Evaluation must test refusal</h3><p>Accuracy tests usually ask whether the system finds the right answer. Security evaluation must also ask whether it refuses the wrong user, cites the wrong version, retrieves across tenants, follows instructions embedded in a document or exposes restricted content through a summary.</p><p>The system should be measured on authorized relevanceâ€”not relevance alone.</p></div></div><div class="pullquote" style="margin-top:18px">In production RAG, relevance without permission is a data leak; permission without provenance is an unverifiable answer.</div></div></div><div class="folio">25</div></section><section class="page white" id="page-26"><div class="running"><strong>RESEARCH BRIEF</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">THE SYSTEM QUIETLY BECAME DIFFERENT</div><h1 class="display small">Uptime is not continued correctness.</h1><p class="lead" style="margin-top:13px">An AI system can remain available while its behavior, inputs, controls or operating context drift away from the assumptions under which it was approved.</p><div class="drift-chart"><svg viewBox="0 0 650 275" fill="none"><path d="M0 64C80 66 120 63 185 69S300 72 365 74S490 76 650 80" stroke="#1f55d9" stroke-width="3"/><path d="M0 112C90 105 140 118 215 111S320 132 410 120S520 147 650 137" stroke="#e45f35" stroke-width="3"/><path d="M0 155C90 160 170 144 250 163S370 149 450 172S540 162 650 180" stroke="#08766c" stroke-width="3"/><path d="M0 201C90 198 165 205 240 198S340 198 410 214S540 208 650 227" stroke="#8265a7" stroke-width="3"/><path d="M0 235C80 232 160 236 240 234S330 229 410 242S550 245 650 251" stroke="#6b747b" stroke-width="3"/><path d="M520 0V275" stroke="#ba2d25" stroke-width="2" stroke-dasharray="5 5"/><text x="529" y="18" font-family="Courier New" font-size="8" fill="#ba2d25">CONTROL STILL GREEN</text></svg></div><div class="drift-legend"><div>BEHAVIORAL</div><div>NUMERICAL</div><div>DATA</div><div>POLICY</div><div>WORKFLOW</div></div><div class="cols2" style="margin-top:16px"><div class="copy"><h3>Five different failures</h3><p><b>Behavioral drift</b> changes response patterns. <b>Numerical drift</b> changes calculated outputs. <b>Data drift</b> changes the input population. <b>Policy drift</b> makes controls outdated. <b>Workflow drift</b> changes how people use the system.</p></div><div class="copy"><h3>One monitoring mistake</h3><p>Teams often treat availability, latency and error rate as proof that the system remains correct. Those measures show whether the service is running. They do not show whether the original operating assumptions remain valid.</p></div></div><div class="pullquote" style="margin-top:14px">A healthy endpoint can still produce a system that is no longer operating inside its original assumptions.</div></div></div><div class="source">Research brief separates behavioral, numerical, data, policy and workflow drift; the concepts require different measurements.</div><div class="folio">26</div></section><section class="page lab-page" id="page-27"><div class="running"><strong>LAB NOTES</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">WHY I OPEN-SOURCED THE SAFETY LAYER</div><h1 class="display small">A guardrail should state what it cannot prove.</h1><p class="lead" style="margin-top:12px">Many teams do not need another model call for basic output checks. They need a small, inspectable layer that makes predictable failures visible before the response reaches the user or tool.</p><div class="lab-terminal"><span class="green">$ llmverify check response.json</span><br>FORMAT ............... PASS<br>PII PATTERN .......... <span class="orange">REVIEW</span><br>INJECTION MARKER ..... PASS<br>JSON REPAIR .......... NOT REQUIRED<br>LATENCY BUDGET ....... PASS<br>FACTUAL TRUTH ........ <span class="orange">NOT ESTABLISHED</span></div><div class="limits"><div class="limit"><b>What deterministic checks can do</b><p>Validate schemas, detect configured injection patterns, flag common PII forms, compare response structure, enforce limits and produce repeatable indicators.</p></div><div class="limit no"><b>What they cannot prove</b><p>That a claim is true, that a user is authorized, that a policy is legally sufficient or that every unsafe behavior has been discovered.</p></div></div><div class="cols2" style="margin-top:15px"><div class="copy"><h3>Why local processing matters</h3><p>A basic safety layer should be inspectable, testable and deployable without creating another opaque dependency. Local checks can reduce unnecessary telemetry and make the rule responsible for a finding visible to the developer.</p></div><div class="copy"><h3>Why limitations belong in the interface</h3><p>Risk indicators become dangerous when users interpret them as verification. â€œHallucination riskâ€ is not the same as factual truth. A responsible control labels the boundary between what it measured and what still requires judgment.</p></div></div><div style="position:absolute;right:.55in;bottom:.55in;display:flex;align-items:end;gap:10px"><div class="print-url">SUBODHKC.COM/PRODUCTS</div><img class="qr" src="/magazine/img-5.png" alt="QR to SubodhKC research and products"></div></div></div><div class="source">llmverify is presented as an open-source control layer. Package version, install counts and telemetry claims should be verified at editorial lock.</div><div class="folio">27</div></section><section class="page field-page" id="page-28"><div class="running"><strong>OPERATOR'S FIELD NOTES</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">FOUR RULES FOR OPERATING AI</div><h1 class="display small">Rules that survive contact with production.</h1><div class="rules4"><div class="rulecard"><div class="n">01</div><h3>Do not automate a workflow nobody owns.</h3><p>Automation removes visible labor; it does not remove accountability for the result.</p></div><div class="rulecard"><div class="n">02</div><h3>Do not give an agent authority you cannot reconstruct.</h3><p>The permission, source, tool and human decision should remain visible after execution.</p></div><div class="rulecard"><div class="n">03</div><h3>Do not call a fallback a recovery plan.</h3><p>A recovery path preserves state, protects the user and creates a usable next action.</p></div><div class="rulecard"><div class="n">04</div><h3>Do not treat a dashboard as an evidence package.</h3><p>Operational visibility and defensibility are related but different requirements.</p></div></div><div class="kicker" style="margin-top:22px;color:#071927">WHEN THE MEETING IS STUCK: CHANGE THE THINKING MODE</div><div class="reset-frame"><div><b>SCAN</b><p>What do we know, directly and verifiably?</p></div><div><b>KNOW</b><p>What are we assuming, avoiding or missing?</p></div><div><b>COMMIT</b><p>Who owns the next decision, by when?</p></div></div><div class="side-note" style="margin-top:16px"><b>FIELD PRACTICE</b><p>The purpose is not to create another framework. It is to force a stalled discussion from competing narratives into shared facts, explicit uncertainty and assigned action.</p></div></div></div><div class="folio">28</div></section><section class="page f3-opener" id="page-29"><div class="feature-tag" style="position:absolute;left:.58in;top:.68in;font:700 8px 'Courier New';letter-spacing:.14em;text-transform:uppercase">Feature 03 · Governance & evidence</div><h1 class="headline">DASHBOARDS<br>ARE NOT<br>EVIDENCE</h1><div class="redactions"><div class="redact"></div><div class="redact short"></div><div class="redact"></div><div class="redact short"></div><div class="redact teal"></div><div style="font:700 7px 'Courier New';margin-top:14px">ACTIVITY VISIBLE<br>AUTHORITY MISSING<br>CONTROL UNBOUND</div></div><p class="dek">A dashboard reports what a system says happened. Defensibility requires proving which instructions, data, authority, tools, tests and controls governed the event.</p><div class="folio">29</div></section><section class="page white" id="page-30"><div class="running"><strong>FEATURE 03 · DASHBOARDS ARE NOT EVIDENCE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">ACCOUNTABILITY CROSSES INVISIBLE LAYERS</div><h1 class="display small">The decision passed through more layers than the evidence preserved.</h1><div class="evidence-stack"><div class="e-layer"><strong>1</strong><b>Business purpose</b><span>Why the system exists</span><i class="">OWNER + BASELINE<br>PRESENT</i></div><div class="e-layer"><strong>2</strong><b>Policy and requirement</b><span>What rule applies</span><i class="">SOURCE + VERSION<br>PRESENT</i></div><div class="e-layer"><strong>3</strong><b>System instruction</b><span>How the model is bounded</span><i class="dotted">PROMPT VERSION<br>MISSING</i></div><div class="e-layer"><strong>4</strong><b>Application instruction</b><span>Workflow-specific direction</span><i class="">CODE + CONFIG<br>PRESENT</i></div><div class="e-layer"><strong>5</strong><b>Retrieved context</b><span>Which evidence influenced it</span><i class="dotted">SOURCE + ACCESS<br>MISSING</i></div><div class="e-layer"><strong>6</strong><b>User identity and input</b><span>Who asked and what they supplied</span><i class="">IDENTITY EVENT<br>PRESENT</i></div><div class="e-layer"><strong>7</strong><b>Tool authority</b><span>What action was permitted</span><i class="dotted">ROLE + LIMIT<br>MISSING</i></div><div class="e-layer"><strong>8</strong><b>Model behavior</b><span>What the model produced</span><i class="">RESPONSE EVENT<br>PRESENT</i></div><div class="e-layer"><strong>9</strong><b>Result and human action</b><span>What changed and who accepted it</span><i class="dotted">OUTCOME RECORD<br>PARTIAL</i></div></div><div class="cols2" style="margin-top:15px"><div class="copy"><p>Each layer may have a different owner, version, storage system and retention period. A dashboard may summarize the final event while the instruction, source or permission that governed it lives elsewhereâ€”or was never preserved.</p></div><div class="copy"><p>Accountability does not disappear because nobody cared. It disappears because the evidence architecture was designed for application activity, not for reconstructing AI authority across layers.</p></div></div><div class="pullquote" style="margin-top:14px">Visibility tells you that something happened. Evidence connects what happened to why it was allowed.</div></div></div><div class="source">The nine-layer model is adapted from the Instruction Stack Audit Framework and HAIEC technical methodology. It is not an accredited audit standard.</div><div class="folio">30</div></section><section class="page warm" id="page-31"><div class="running"><strong>FEATURE 03 · DASHBOARDS ARE NOT EVIDENCE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">TRACE ONE CONSEQUENTIAL REQUEST</div><h1 class="display small">â€œCancel my appointment and refund the deposit.â€</h1><p class="lead" style="margin-top:12px">A fluent response is the least important evidence. The defensible chain must show what governed the action and which boundary stopped the system from exceeding its authority.</p><div class="decision-chain"><div class="decision-step"><b>BUSINESS RULE</b><p>Cancellation permitted before service; deposits require defined approval.</p><span>Policy v4.2</span></div><div class="decision-step"><b>IDENTITY</b><p>Caller identity and appointment ownership are verified.</p><span>Identity event</span></div><div class="decision-step"><b>RETRIEVAL</b><p>Current cancellation and refund policy is loaded.</p><span>Source + version</span></div><div class="decision-step"><b>AUTHORITY</b><p>AI may cancel; refund above threshold requires approval.</p><span>Role + limit</span></div><div class="decision-step"><b>TOOL ACTION</b><p>Calendar cancellation succeeds; refund remains pending.</p><span>Tool result</span></div><div class="decision-step"><b>HUMAN DECISION</b><p>Authorized manager approves the exception.</p><span>Approval record</span></div><div class="decision-step"><b>OUTCOME</b><p>Customer informed; refund ID and owner recorded.</p><span>Bound artifact</span></div></div><div class="cols2" style="margin-top:14px"><div class="copy"><h3>What a dashboard might show</h3><p>Request completed. Calendar tool used. Response time within target. No system error.</p><p>All of that can be correct while the crucial question remains unanswered: Why was the AI allowed to cancel but not refund?</p></div><div class="copy"><h3>What the evidence chain must add</h3><p>The applicable policy, instruction version, verified identity, authority limit, tool result, human approval and final artifact must remain connected.</p><div class="side-note orange"><b>FAILURE MODE</b><p>The organization assembles the story only after the customer challenges the decision.</p></div></div></div></div></div><div class="folio">31</div></section><section class="page white" id="page-32"><div class="running"><strong>FEATURE 03 · DASHBOARDS ARE NOT EVIDENCE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">INTERPRET BROADLY. VERIFY PRECISELY.</div><h1 class="display small">Probabilistic analysis and deterministic control solve different problems.</h1><p class="lead" style="margin-top:12px">The strategic error is not using one or the other. It is asking either approach to prove what it cannot establish.</p><div class="compare"><div class="compare-box"><h3>AI-assisted interpretation</h3><ul><li>Useful for ambiguous context and triage</li><li>Can discover patterns not already encoded</li><li>May vary with model, prompt and context</li><li>Requires review and judgment</li><li>Should not be mistaken for a repeatable gate</li></ul></div><div class="compare-box det"><h3>Deterministic verification</h3><ul><li>Useful for defined conditions and release gates</li><li>Produces explicit findings under a versioned ruleset</li><li>Can repeat when input and configuration remain the same</li><li>Supports regression testing and evidence artifacts</li><li>Does not resolve every ambiguous or legal question</li></ul></div></div><div class="cols2"><div class="copy"><h3>The stronger architecture combines them</h3><p>Use probabilistic analysis to discover, prioritize and interpret. Use deterministic checks to verify known conditions, enforce gates and create repeatable results. Use human judgment where context, consequence or law cannot be reduced to a fixed rule.</p></div><div class="copy"><h3>The wording matters</h3><p>A deterministic engine can be designed to return the same result for the same input, ruleset and configuration. That does not mean the rule is complete, the evidence will be accepted by every reviewer or the system is â€œcompliant.â€</p></div></div><div class="pullquote" style="margin-top:16px">Reproducibility strengthens evidence. It does not eliminate scope, interpretation or accountability.</div></div></div><div class="folio">32</div></section><section class="page warm" id="page-33"><div class="running"><strong>FEATURE 03 · DASHBOARDS ARE NOT EVIDENCE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">BIND THE CLAIM TO THE CONTROL</div><h1 class="display small">A statement becomes evidence only when the chain is connected.</h1><div class="claim-chain"><div class="claim-node"><b>CLAIM</b><span>Unauthorized tool use is prevented</span></div><div class="claim-node"><b>REQUIREMENT</b><span>Only approved roles may execute</span></div><div class="claim-node"><b>CONTROL</b><span>Gateway checks role and limit</span></div><div class="claim-node"><b>IMPLEMENTATION</b><span>Policy + middleware</span></div><div class="claim-node"><b>TEST</b><span>Unauthorized role attempts action</span></div><div class="claim-node"><b>RESULT</b><span>Blocked and logged</span></div><div class="claim-node"><b>ARTIFACT</b><span>Version, time, hash, owner</span></div></div><div class="cols2" style="margin-top:18px"><div class="copy"><h3>Start with the claim</h3><p>â€œThe system prevents unauthorized tool executionâ€ sounds concrete. It is still only a statement until the organization identifies the requirement, implementation and test that support it.</p><p>The chain must also preserve versions. A passing test against last monthâ€™s policy does not establish that todayâ€™s configuration is controlled.</p><h3>Evidence must carry context</h3><p>A test result without scope, system identity, ruleset, environment, timestamp and owner may be difficult to reproduce or interpret later.</p></div><div class="copy"><h3>Do not bind after the fact</h3><p>When teams assemble evidence only after a customer or auditor asks, they often match artifacts to claims by inference. The code may have changed. The prompt may not have been versioned. A screenshot may lack the underlying source.</p><p>Evidence binding should be part of release and change managementâ€”not a separate documentation project after the incident.</p><div class="side-note teal"><b>EVIDENCE TRAIL</b><p>Claim · source · control · implementation · test · result · version · owner · limitation.</p></div></div></div><div class="pullquote" style="margin-top:17px">A claim without a bound test is only a statement.</div></div></div><div class="folio">33</div></section><section class="page white" id="page-34"><div class="running"><strong>FEATURE 03 · DASHBOARDS ARE NOT EVIDENCE</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.45in"><div class="kicker">BUILD THE PROOF WHILE YOU BUILD THE SYSTEM</div><h1 class="display small">After the incident, disconnected records may explain. They may not prove.</h1><div class="cols2" style="margin-top:17px"><div class="copy"><h3>Preserve the operating context</h3><p>For every production capability, retain the business purpose, named owner, applicable requirement, prompt and policy version, data-source version, identity decision, tool permission, test result, release approval, exception, human override, incident history and artifact-integrity information.</p><p>The exact set should match the consequence. A low-risk drafting assistant may require far less evidence than an agent authorized to affect customer money, employment or access.</p><h3>Design retention intentionally</h3><p>Evidence that expires before the dispute arrives is not useful. Retention periods should consider customer commitments, incident investigation, regulatory timing and the ability to reproduce the deployed configuration.</p></div><div class="copy"><h3>Use this Monday</h3><p>Select one production AI interaction. List every instruction, source, permission and tool involved. Identify the artifact that proves each control operated. Mark where the chain becomes incomplete. Assign an owner and retention period.</p><p>Then ask a harder question: could someone outside the build team understand the record six months from now?</p><div class="side-note orange"><b>DISCLOSURE</b><p>HAIEC is one implementation example used by the editor. Framework mapping and generated artifacts support review; they are not certification or a guarantee of audit or legal acceptance.</p></div></div></div><div class="pullquote" style="margin-top:22px">Build the proof while you build the system. Once the challenge arrives, explanation is easier to create than evidence.</div></div></div><div class="folio">34</div></section><section class="page sources-page" id="page-35"><div class="running"><strong>SOURCES · STATUS · DISCLOSURES</strong><span>AI THAT WORKS · ISSUE 01</span></div><div class="page-inner"><div style="margin-top:.43in"><div class="kicker">SOURCE TRAIL</div><h1 class="display small">Read the complete work.</h1><div class="sources-grid"><div><div class="source-item"><b>Cognitive Systems Management and research index</b><span>SUBODHKC.COM/RESEARCH</span></div><div class="source-item"><b>Why AI Voice Agents Fail in Production</b><span>SUBODHKC.COM/WHY-AI-VOICE-AGENTS-FAIL-IN-PRODUCTION</span></div><div class="source-item"><b>Secure Enterprise RAG Architecture</b><span>SUBODHKC.COM/SECURE-ENTERPRISE-RAG-ARCHITECTURE</span></div><div class="source-item"><b>HAIEC technical platform and methodology</b><span>HAIEC.COM</span></div><div class="source-item"><b>Kestrel Voice product and workflow documentation</b><span>KESTRELVOICE.COM</span></div><div class="source-item"><b>FrontOfAI weekly intelligence briefing</b><span>FRONTOFAI.COM/BRIEFING</span></div></div><div><h3 style="border-top:4px solid var(--ink);padding-top:9px">Project status language</h3><div class="status-key" style="margin-top:9px"><div><b>LIVE</b>Publicly operating capability.</div><div><b>PRIVATE BETA</b>Limited invited use; configuration varies.</div><div><b>OPEN SOURCE</b>Repository or package released under stated license.</div><div><b>RESEARCH</b>Paper or practitioner methodology; not automatically peer reviewed.</div><div><b>ILLUSTRATIVE</b>Reconstructed example or visual.</div><div><b>CONDITIONAL</b>Capability depends on tested configuration.</div></div><h3 style="margin-top:14px">Editorial disclosures</h3><p class="caption" style="margin-top:7px">Subodh KC is the founder of HAIEC and Kestrel Voice and publishes FrontOfAI and llmverify-related work. Product references appear as implementation evidence and are labeled. Framework mapping is not certification. Legal content is general information, not legal advice. Reconstructed call traces contain no customer identifiers.</p><h3 style="margin-top:13px">Masthead</h3><p class="caption" style="margin-top:6px"><b>Editor and publisher:</b> Subodh KC<br><b>Issue:</b> AI That Works · No. 01 · 2026<br><b>Theme:</b> From Demo to Operating System<br><b>Contact:</b> SUBODHKC.COM/CONTACT</p></div></div><div class="sponsor-strip"><div><div class="kicker" style="color:#071927;margin-bottom:5px">ADVERTISEMENT OPPORTUNITY · ISSUE 02</div><h3>Reach leaders responsible for making AI work after the demo.</h3><p>Founding placements for AI infrastructure, security, data, governance, developer tools and enterprise services. Advertising is labeled and does not purchase editorial coverage.</p><div class="print-url" style="margin-top:6px">SUBODHKC.COM/CONTACT</div></div><img class="qr" src="/magazine/img-8.png" alt="QR code for advertiser inquiry"></div></div></div><div class="folio">35</div></section><section class="page ad-kestrel" id="page-36"><div class="ad-label" style="color:#a8bfca">Advertisement</div><div class="mark"><svg viewBox="0 0 24 24" fill="none" aria-label="Kestrel mark"><path d="M4 4.5L20 2L12.4 9.6L20 22L4 13.4L9.6 9.4L4 4.5Z" fill="#0B63F6" opacity=".88"/><path d="M9.6 9.4L20 2L12.4 9.6L20 22L9.6 9.4Z" fill="#93C5FD" opacity=".7"/></svg></div><div class="copy"><div class="brand-lock"><div class="tiny"><svg viewBox="0 0 24 24" fill="none" aria-label="Kestrel mark"><path d="M4 4.5L20 2L12.4 9.6L20 22L4 13.4L9.6 9.4L4 4.5Z" fill="#0B63F6" opacity=".88"/><path d="M9.6 9.4L20 2L12.4 9.6L20 22L9.6 9.4Z" fill="#93C5FD" opacity=".7"/></svg></div>KESTREL VOICE · PRIVATE BETA</div><h1>THE PHONE RANG.<br>DID THE <span>WORKFLOW MOVE?</span></h1><div class="sub">From first ring to a recorded next action.</div></div><div class="kestrel-wave"><svg viewBox="0 0 240 64" fill="none" aria-label="Live call waveform"><g stroke="#0B63F6" stroke-width="3" stroke-linecap="round"><path d="M9.6 27V37M19.2 23V41M28.8 18V46M38.4 24V40M48 14V50M57.6 10V54M67.2 21V43M76.8 23V41M86.4 12V52M96 5V59M105.6 18V46M115.2 22V42M124.8 25V39M134.4 16V48M144 9V55M153.6 15V49M163.2 20V44M172.8 24V40M182.4 19V45M192 13V51M201.6 6V58M211.2 17V47M220.8 23V41M230.4 26V38"/></g></svg></div><div class="k-workflow"><div class="k-step"><div class="svg-icon"><svg viewBox="0 0 24 24" fill="none"><path d="M8.2 4.5l2 3.5c.3.5.2 1.2-.3 1.6l-1.2 1c1.1 2.2 2.8 3.9 5 5l1-1.2c.4-.5 1.1-.6 1.6-.3l3.5 2c.6.3.8 1 .6 1.6-.6 1.7-2.2 2.8-4 2.8C9.7 20.5 3.5 14.3 3.5 7.6c0-1.8 1.1-3.4 2.8-4 .6-.2 1.3 0 1.6.6Z" stroke="#0B63F6" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round"/></svg></div><b>Incoming</b><span>A customer calls with a real request.</span></div><div class="k-step"><div class="svg-icon"><svg viewBox="0 0 24 24" fill="none"><path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5Z" fill="#0B63F6"/><path d="M18 15l1 2.5 2.5 1-2.5 1-1 2.5-1-2.5-2.5-1 2.5-1 1-2.5Z" fill="#0B63F6" opacity=".55"/></svg></div><b>AI answers</b><span>Approved business knowledge guides the response.</span></div><div class="k-step"><div class="svg-icon"><svg viewBox="0 0 24 24" fill="none"><rect x="4" y="5.5" width="16" height="14" rx="2.5" stroke="#F97316" stroke-width="1.7"/><path d="M8 3.5v4M16 3.5v4M4 9.5h16M8 13h3M13 13h3M8 16h3" stroke="#F97316" stroke-width="1.5" stroke-linecap="round"/></svg></div><b>Action captured</b><span>The request is routed or a next step is recorded.</span></div><div class="k-step"><div class="svg-icon"><svg viewBox="0 0 24 24" fill="none"><path d="M18 8a6 6 0 1 0-12 0c0 7-3 7-3 9h18c0-2-3-2-3-9Z" stroke="#0B63F6" stroke-width="1.7" stroke-linejoin="round"/><path d="M9.5 20a2.8 2.8 0 0 0 5 0" stroke="#0B63F6" stroke-width="1.7" stroke-linecap="round"/></svg></div><b>Team notified</b><span>The business receives the context and ownership.</span></div></div><div class="k-status"><b>NOW AVAILABLE.</b> Availability and supported actions vary by configuration. Appointment and system integrations should be represented only where the specific configuration has passed acceptance testing.</div><div class="ad-foot"><div><div class="print-url">KESTRELVOICE.COM</div><div class="ad-small">AI voice operations for businesses that cannot afford missed demand.</div></div><div class="ad-qr"><span class="ad-small">Production information</span><img class="qr" src="/magazine/img-9.png" alt="QR code to Kestrel Voice"></div></div><div class="folio">36</div></section></main>`;
